import { useEffect, useState } from "react";
import courseService from "../services/courseService";
import { useAuth } from "../context/AuthContext";
import LoadingSpinner from "../components/LoadingSpinner";

const CoursesPage = () => {
  const { isAdmin } = useAuth();
  const [courses, setCourses] = useState([]);
  const [loading, setLoading] = useState(true);
  const [message, setMessage] = useState("");
  const [error, setError] = useState("");
  const [form, setForm] = useState({ title: "", instructorId: "" });
  const [editingId, setEditingId] = useState(null);
  const [editForm, setEditForm] = useState({ title: "", instructorId: "" });

  const loadCourses = async () => {
    setLoading(true);
    setError("");
    try {
      const response = await courseService.getAll();
      if (response.success) {
        setCourses(response.data || []);
      } else {
        setError(response.message || "Failed to load courses.");
      }
    } catch (err) {
      setError(err.message || "Failed to load courses.");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    loadCourses();
  }, []);

  const handleCreate = async (event) => {
    event.preventDefault();
    setMessage("");
    setError("");

    try {
      const response = await courseService.create({
        title: form.title,
        instructorId: Number(form.instructorId)
      });
      if (response.success) {
        setMessage(response.message);
        setCourses((prev) => [...prev, response.data]);
        setForm({ title: "", instructorId: "" });
        return;
      }
      setError(response.message || "Failed to create course.");
    } catch (err) {
      setError(err.message || "Failed to create course.");
    }
  };

  const startEdit = (course) => {
    setEditingId(course.id);
    setEditForm({
      title: course.title,
      instructorId: course.instructorId || ""
    });
  };

  const handleUpdate = async (event) => {
    event.preventDefault();
    if (!editingId) return;
    setMessage("");
    setError("");

    try {
      const response = await courseService.update(editingId, {
        title: editForm.title,
        instructorId: Number(editForm.instructorId)
      });
      if (response.success) {
        setMessage(response.message);
        setCourses((prev) =>
          prev.map((item) => (item.id === editingId ? response.data : item))
        );
        setEditingId(null);
        return;
      }
      setError(response.message || "Failed to update course.");
    } catch (err) {
      setError(err.message || "Failed to update course.");
    }
  };

  return (
    <section>
      <div className="page-header">
        <h2>Courses</h2>
        <p className="muted">Create and manage course offerings.</p>
      </div>

      {isAdmin && (
        <div className="card">
          <h3>Create course</h3>
          <form onSubmit={handleCreate} className="form-grid">
            <div className="form-group">
              <label>Title</label>
              <input
                name="title"
                value={form.title}
                onChange={(event) =>
                  setForm((prev) => ({ ...prev, title: event.target.value }))
                }
                required
              />
            </div>
            <div className="form-group">
              <label>Instructor Id</label>
              <input
                name="instructorId"
                type="number"
                value={form.instructorId}
                onChange={(event) =>
                  setForm((prev) => ({
                    ...prev,
                    instructorId: event.target.value
                  }))
                }
                required
              />
            </div>
            <div className="actions">
              <button className="btn btn-primary" type="submit">
                Create
              </button>
            </div>
          </form>
        </div>
      )}

      <div className="card">
        <h3>Course list</h3>
        {loading ? (
          <LoadingSpinner />
        ) : (
          <table className="table">
            <thead>
              <tr>
                <th>Id</th>
                <th>Title</th>
                <th>Instructor Id</th>
                {isAdmin && <th>Actions</th>}
              </tr>
            </thead>
            <tbody>
              {courses.map((course) => (
                <tr key={course.id}>
                  <td>{course.id}</td>
                  <td>{course.title}</td>
                  <td>{course.instructorId}</td>
                  {isAdmin && (
                    <td>
                      <button
                        className="btn btn-secondary"
                        onClick={() => startEdit(course)}
                      >
                        Edit
                      </button>
                    </td>
                  )}
                </tr>
              ))}
              {courses.length === 0 && (
                <tr>
                  <td colSpan={isAdmin ? 4 : 3} className="muted">
                    No courses found.
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        )}
      </div>

      {isAdmin && editingId && (
        <div className="card">
          <h3>Edit course #{editingId}</h3>
          <form onSubmit={handleUpdate} className="form-grid">
            <div className="form-group">
              <label>Title</label>
              <input
                name="title"
                value={editForm.title}
                onChange={(event) =>
                  setEditForm((prev) => ({ ...prev, title: event.target.value }))
                }
                required
              />
            </div>
            <div className="form-group">
              <label>Instructor Id</label>
              <input
                name="instructorId"
                type="number"
                value={editForm.instructorId}
                onChange={(event) =>
                  setEditForm((prev) => ({
                    ...prev,
                    instructorId: event.target.value
                  }))
                }
                required
              />
            </div>
            <div className="actions">
              <button className="btn btn-primary" type="submit">
                Save
              </button>
              <button
                className="btn btn-secondary"
                type="button"
                onClick={() => setEditingId(null)}
              >
                Cancel
              </button>
            </div>
          </form>
        </div>
      )}

      {message && <div className="alert alert-success">{message}</div>}
      {error && <div className="alert alert-error">{error}</div>}
    </section>
  );
};

export default CoursesPage;
